def solve(pao2_fio2_ratio, respiratory_support, platelets, gcs, bilirubin, map, dopamine_dose, dobutamine_administered, epinephrine_dose, norepinephrine_dose, creatinine, urine_output):
    # Step 1: PaO2/FiO2 ratio score calculation
    if pao2_fio2_ratio >= 400:
        respiratory_score = 0
    elif 300 <= pao2_fio2_ratio <= 399:
        respiratory_score = 1
    elif 200 <= pao2_fio2_ratio <= 299:
        respiratory_score = 2
    elif 100 <= pao2_fio2_ratio <= 199:
        if respiratory_support:
            respiratory_score = 3
        else:
            respiratory_score = 0  # default when no respiratory support
    else:  # pao2_fio2_ratio < 100
        if respiratory_support:
            respiratory_score = 4
        else:
            respiratory_score = 0

    yield {
        "step_name": "pao2_fio2_ratio_score",
        "step_description": "Calculate the SOFA score for the PaO2/FiO2 ratio criterion based on the ratio value and respiratory support status.",
        "step_result": respiratory_score,
        "unit": None
    }

    # Step 2: Platelets score calculation
    if platelets >= 150:
        platelets_score = 0
    elif 100 <= platelets <= 149:
        platelets_score = 1
    elif 50 <= platelets <= 99:
        platelets_score = 2
    elif 20 <= platelets <= 49:
        platelets_score = 3
    else:  # platelets < 20
        platelets_score = 4

    yield {
        "step_name": "platelets_score",
        "step_description": "Calculate the SOFA score for the Platelets criterion based on the platelet count.",
        "step_result": platelets_score,
        "unit": None
    }

    # Step 3: GCS score calculation
    if gcs == 15:
        gcs_score = 0
    elif 13 <= gcs <= 14:
        gcs_score = 1
    elif 10 <= gcs <= 12:
        gcs_score = 2
    elif 6 <= gcs <= 9:
        gcs_score = 3
    else:  # gcs < 6
        gcs_score = 4

    yield {
        "step_name": "gcs_score",
        "step_description": "Calculate the SOFA score for the Glasgow Coma Scale criterion based on the GCS value.",
        "step_result": gcs_score,
        "unit": None
    }

    # Step 4: Bilirubin score calculation
    if bilirubin < 1.2:
        bilirubin_score = 0
    elif 1.2 <= bilirubin <= 1.9:
        bilirubin_score = 1
    elif 2.0 <= bilirubin <= 5.9:
        bilirubin_score = 2
    elif 6.0 <= bilirubin <= 11.9:
        bilirubin_score = 3
    else:  # bilirubin >= 12.0
        bilirubin_score = 4

    yield {
        "step_name": "bilirubin_score",
        "step_description": "Calculate the SOFA score for the Bilirubin criterion based on the bilirubin level.",
        "step_result": bilirubin_score,
        "unit": None
    }

    # Step 5: Cardiovascular score calculation
    # Check conditions in order of increasing severity, highest score wins
    cardiovascular_score = 0

    # Check for no hypotension and no vasopressors
    no_vasopressors = (dopamine_dose == 0 and dobutamine_administered == False 
                       and epinephrine_dose == 0 and norepinephrine_dose == 0)

    if map >= 70 and no_vasopressors:
        cardiovascular_score = max(cardiovascular_score, 0)

    # MAP < 70 and no vasopressors
    if map < 70 and no_vasopressors:
        cardiovascular_score = max(cardiovascular_score, 1)

    # dopamine <= 5 OR dobutamine administered
    if dopamine_dose <= 5 or dobutamine_administered:
        cardiovascular_score = max(cardiovascular_score, 2)

    # (dopamine > 5 and <= 15) OR epinephrine <= 0.1 OR norepinephrine <= 0.1
    if (5 < dopamine_dose <= 15) or epinephrine_dose <= 0.1 or norepinephrine_dose <= 0.1:
        cardiovascular_score = max(cardiovascular_score, 3)

    # dopamine > 15 OR epinephrine > 0.1 OR norepinephrine > 0.1
    if dopamine_dose > 15 or epinephrine_dose > 0.1 or norepinephrine_dose > 0.1:
        cardiovascular_score = max(cardiovascular_score, 4)

    yield {
        "step_name": "cardiovascular_score",
        "step_description": "Calculate the SOFA score for the Cardiovascular criterion based on MAP and vasopressor administration.",
        "step_result": cardiovascular_score,
        "unit": None
    }

    # Step 6: Renal score calculation (use higher of creatinine or urine output criteria)
    renal_score = 0

    # Creatinine-based scoring
    if creatinine < 1.2:
        renal_score = max(renal_score, 0)
    elif 1.2 <= creatinine <= 1.9:
        renal_score = max(renal_score, 1)
    elif 2.0 <= creatinine <= 3.4:
        renal_score = max(renal_score, 2)
    elif 3.5 <= creatinine <= 4.9:
        renal_score = max(renal_score, 3)
    elif creatinine >= 5.0:
        renal_score = max(renal_score, 4)

    # Urine output-based scoring
    if urine_output < 500:
        renal_score = max(renal_score, 3)
    if urine_output < 200:
        renal_score = max(renal_score, 4)

    yield {
        "step_name": "renal_score",
        "step_description": "Calculate the SOFA score for the Renal criterion based on creatinine level or urine output.",
        "step_result": renal_score,
        "unit": None
    }

    # Step 7: Total SOFA score calculation
    total_sofa_score = respiratory_score + platelets_score + gcs_score + bilirubin_score + cardiovascular_score + renal_score

    yield {
        "step_name": "total_sofa_score",
        "step_description": "Calculate the total SOFA score by summing the individual criterion scores.",
        "step_result": total_sofa_score,
        "unit": None
    }

    return total_sofa_score
